INSERT INTO `live_blog` (`id`, `titulo`, `slug`, `descripcion`, `imagen`, `estado`, `categoria_id`, `autor_id`, `total_updates`, `vistas`, `fecha_inicio`, `fecha_fin`, `fecha_creacion`) VALUES
(1, 'INTENTO DE ASESINATO DE DONALD TRUMP', 'intento-de-asesinato-de-donald-trump', 'Trump dice que el sospechoso del tiroteo en la Cena de Corresponsales actuó por odio a los cristianos', 'https://elclickrd.com/assets/images/noticias/img_1777173634_7fd50642.jpg', 'finalizado', 6, 1, 5, 30, '2026-05-03 05:45:36', '2026-05-04 20:37:45', '2026-05-03 05:45:36');
INSERT INTO `live_blog_updates` (`id`, `blog_id`, `autor_id`, `contenido`, `tipo`, `imagen`, `video_url`, `es_destacado`, `fecha`) VALUES
(1, 1, 1, 'En estos momentos el presidente Donald Trump da una rueda de prensa sobre el tiroteo', 'texto', NULL, NULL, 0, '2026-05-03 05:46:53'),
(3, 1, 1, 'Imagenes de la rueda de prensa', 'imagen', 'https://elclickrd.com/assets/images/noticias/media_1777787382_26e4e424.jpg', NULL, 0, '2026-05-03 05:50:34'),
(4, 1, 1, 'Trump divulga una foto del sospechoso de disparar en la cena de corresponsales', 'video', NULL, 'https://www.youtube.com/watch?v=FX6Rte87IuY', 0, '2026-05-03 05:52:27'),
(5, 1, 5, 'El prosidente Donald Trump acaba de salir de la actividad para el bumker de seguridad de la casa blanca', 'texto', NULL, NULL, 0, '2026-05-04 20:31:58'),
(6, 1, 5, 'Nuevas imagenes del atentado', 'video', NULL, 'https://youtu.be/KKBkwZmad4k?si=bbbe1xVUuKvtMNvO', 0, '2026-05-04 20:33:26');
INSERT INTO `noticias` (`id`, `titulo`, `slug`, `resumen`, `contenido`, `imagen`, `imagen_alt`, `imagen_caption`, `autor_id`, `categoria_id`, `vistas`, `compartidos`, `likes`, `estado`, `destacado`, `breaking`, `es_premium`, `es_opinion`, `allow_comments`, `fuente`, `fuente_url`, `video_url`, `audio_url`, `tiempo_lectura`, `encuesta_id`, `meta_title`, `meta_description`, `keywords`, `fecha_publicacion`, `fecha_actualizacion`, `fecha_creacion`, `total_compartidos`, `total_reacciones`, `tiene_encuesta`, `tiene_live`, `permitir_comentarios`, `latitud`, `longitud`) VALUES
(1, 'Gobierno anuncia inversión de 50 mil millones en infraestructura vial para 2026', 'gobierno-anuncia-inversion-de-50-mil-millones-en-infraestructura-vial-para-2026', 'El presidente presentó un ambicioso plan de construcción y reparación de carreteras que beneficiará a más de 2 millones de ciudadanos en todo el país.', '<p>El <strong>Gobierno de la República Dominicana</strong> anunció este jueves un plan de inversión histórico de <strong>50 mil millones de pesos</strong> destinados a la renovación y construcción de infraestructura vial en todo el territorio nacional durante el año 2026.</p>\r\n<p>El plan, denominado <em>\"RD Conectada 2026\"</em>, contempla la reparación de más de 1,200 kilómetros de carreteras en estado crítico, la construcción de 15 nuevos puentes y la modernización de los principales corredores viales del país.</p>\r\n<h2>Regiones beneficiadas</h2>\r\n<p>Según el ministro de Obras Públicas, las regiones Cibao, Sur y Este serán las principales beneficiadas, donde se concentra el mayor deterioro de la red vial. Se estima que el proyecto generará más de <strong>45,000 empleos directos</strong> en los próximos 24 meses.</p>\r\n<p>La inversión será financiada a través de una combinación de fondos del presupuesto nacional, préstamos del BID y cooperación internacional. Las obras comenzarán en el primer trimestre de 2026.</p>\r\n<h2>Reacciones del sector privado</h2>\r\n<p>El sector empresarial recibió con entusiasmo el anuncio, destacando que la mejora vial tendrá un impacto directo en la reducción de costos logísticos y en la competitividad del país.</p>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=1200&q=80', '', '', 1, 1, 15425, 0, 0, 'publicado', 1, 1, 0, 0, 1, '', '', '', NULL, 1, NULL, '', '', '', '2026-04-24 02:05:00', '2026-05-10 00:32:26', '2026-04-24 01:05:48', 322, 145, 0, 0, 1, NULL, NULL),
(2, 'Inteligencia Artificial dominicana gana premio internacional de innovación en Silicon Valley', 'inteligencia-artificial-dominicana-gana-premio-internacional-de-innovacion-en-silicon-valley', 'Un equipo de ingenieros dominicanos desarrolló un sistema de IA que mejora el diagnóstico de enfermedades tropicales con un 97% de precisión, superando a 140 equipos de 35 países.', '<p>En un hito histórico para la tecnología dominicana, el equipo <strong>TechRD Innovation Lab</strong> se coronó campeón del prestigioso <em>Global AI Health Challenge 2026</em> celebrado en Silicon Valley, California, superando a más de 140 equipos provenientes de 35 países.</p>\r\n<p>El sistema desarrollado, denominado <strong>MediScan DR</strong>, utiliza algoritmos de aprendizaje profundo para detectar enfermedades tropicales como dengue, chikungunya y malaria con una precisión del <strong>97.3%</strong>, a partir de simples análisis de sangre digitalizados.</p>\r\n<h2>El equipo detrás del logro</h2>\r\n<p>El equipo está conformado por seis ingenieros egresados de universidades dominicanas, con edades entre 24 y 31 años. Su líder, la doctora en inteligencia artificial <strong>María Fernández</strong>, señaló que el sistema fue entrenado con datos de pacientes de hospitales públicos del país.</p>\r\n<p>\"Queríamos resolver un problema real de nuestra gente. En las zonas rurales, el diagnóstico tardío de estas enfermedades cuesta vidas\", afirmó Fernández durante la ceremonia de premiación.</p>\r\n<h2>Impacto esperado</h2>\r\n<p>El Ministerio de Salud Pública ya manifestó interés en implementar la tecnología en los principales centros de salud del país. Se estima que podría beneficiar a más de 500,000 pacientes anuales.</p>', 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=1200&q=80', '', '', 1, 3, 28756, 0, 0, 'publicado', 1, 1, 0, 0, 1, '', '', '', NULL, 1, NULL, '', '', '', '2026-04-23 23:05:00', '2026-05-12 00:08:01', '2026-04-23 22:05:48', 512, 289, 0, 0, 1, NULL, NULL),
(3, 'Selección dominicana de fútbol clasifica al Mundial 2026 tras victoria histórica ante México', 'seleccion-dominicana-futbol-clasifica-mundial-2026-victoria-historica-mexico', 'Con un gol en el minuto 94, la Selección Nacional selló su primera clasificación mundialista en la historia del fútbol dominicano ante más de 45,000 espectadores en el Estadio Olímpico.', '<p>Las lágrimas de alegría inundaron el <strong>Estadio Olímpico Félix Sánchez</strong> este martes cuando el delantero <strong>Carlos \"El Toro\" Martínez</strong> anotó el gol definitivo en el minuto 94 de partido para darle a la República Dominicana una victoria de 2-1 ante México y sellar su primera clasificación a una Copa Mundial de la FIFA.</p>\r\n<p>El histórico encuentro fue presenciado por más de <strong>45,000 aficionados</strong> que colmaron el estadio desde tempranas horas de la tarde. Las escenas de celebración se extendieron por todo el país durante toda la noche.</p>\r\n<h2>El partido</h2>\r\n<p>El partido comenzó de manera adversa para los dominicanos cuando México abrió el marcador en el minuto 23. Sin embargo, la reacción del equipo local no tardó en llegar: <strong>Rafael Santos</strong> empató en el minuto 67 con un potente disparo desde fuera del área.</p>\r\n<p>El desenlace llegó en el tiempo de descuento cuando Martínez, quien ingresó como sustituto en el segundo tiempo, recibió un pase filtrado y definió con categoría ante el portero rival.</p>\r\n<h2>Reacciones</h2>\r\n<p>El presidente de la República felicitó a los jugadores desde las redes sociales, mientras el técnico de la selección, el español <strong>Javier Ramos</strong>, se mostró emocionado: \"Esto es para la historia del deporte dominicano\".</p>', 'https://images.unsplash.com/photo-1574629810360-7efbbe195018?w=1200&q=80', NULL, NULL, 1, 4, 67963, 0, 0, 'publicado', 1, 1, 0, 0, 1, NULL, NULL, NULL, NULL, 5, NULL, NULL, NULL, NULL, '2026-04-23 20:05:48', '2026-05-12 02:06:40', '2026-04-23 19:05:48', 1242, 876, 0, 0, 1, NULL, NULL),
(4, 'Economía dominicana crece 6.2% en el primer trimestre de 2026, la más alta de Latinoamérica', 'economia-dominicana-crece-6-2-en-el-primer-trimestre-de-2026-la-mas-alta-de-latinoamerica', 'El Banco Central reportó que el PIB dominicano registró el mayor crecimiento económico de la región, impulsado por el turismo, las zonas francas y la construcción.', '<p>El <strong>Banco Central de la República Dominicana</strong> presentó este lunes los datos económicos del primer trimestre de 2026, revelando un crecimiento del <strong>Producto Interno Bruto (PIB) del 6.2%</strong>, la tasa más alta registrada en América Latina durante el mismo período.</p>\r\n<p>El resultado supera las proyecciones del Fondo Monetario Internacional (FMI), que había estimado un crecimiento del 5.1% para la economía dominicana en 2026.</p>\r\n<h2>Sectores impulsores</h2>\r\n<p>El gobernador del Banco Central destacó que los principales motores del crecimiento fueron:</p>\r\n<ul>\r\n<li><strong>Turismo:</strong> Con un incremento del 18% en llegadas de visitantes extranjeros, alcanzando 3.2 millones en el trimestre.</li>\r\n<li><strong>Zonas Francas:</strong> Las exportaciones crecieron un 12% impulsadas por la demanda de productos médicos y textiles.</li>\r\n<li><strong>Construcción:</strong> El sector registró un alza del 9.8% gracias a proyectos de infraestructura pública y privada.</li>\r\n<li><strong>Remesas:</strong> Los envíos desde el exterior sumaron 2,100 millones de dólares, un récord histórico para el período.</li>\r\n</ul>\r\n<h2>Perspectivas</h2>\r\n<p>Economistas consultados proyectan que la economía dominicana podría cerrar 2026 con un crecimiento anual entre el 5.5% y el 6.0%, consolidando al país como uno de los de mayor dinamismo económico de la región.</p>', 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=1200&q=80', '', '', 1, 2, 9362, 0, 0, 'publicado', 1, 1, 0, 0, 1, '', '', '', NULL, 1, NULL, '', '', '', '2026-04-23 16:05:00', '2026-05-12 02:55:35', '2026-04-23 15:05:48', 187, 92, 0, 0, 1, NULL, NULL),
(5, 'Ministerio de Salud lanza campaña nacional de vacunación gratuita contra el dengue', 'ministerio-de-salud-lanza-campana-nacional-de-vacunacion-gratuita-contra-el-dengue', 'Más de 3 millones de dominicanos serán vacunados de forma gratuita en 1,200 centros de salud de todo el país durante los próximos 60 días.', '<p>El <strong>Ministerio de Salud Pública</strong> lanzó este miércoles la mayor campaña de vacunación contra el dengue en la historia del país, con el objetivo de inmunizar a más de <strong>3 millones de personas</strong> en los próximos 60 días a través de 1,200 centros de salud distribuidos en todo el territorio nacional.</p>\r\n<p>La campaña, denominada <em>\"RD Sin Dengue\"</em>, utilizará la vacuna <strong>Dengvaxia</strong> aprobada por la Organización Mundial de la Salud (OMS), y estará disponible de forma completamente <strong>gratuita</strong> para todos los ciudadanos mayores de 9 años.</p>\r\n<h2>Grupos prioritarios</h2>\r\n<p>En una primera fase, la vacuna será aplicada prioritariamente a:</p>\r\n<ul>\r\n<li>Niños y adolescentes entre 9 y 16 años</li>\r\n<li>Personas mayores de 60 años</li>\r\n<li>Trabajadores de la salud</li>\r\n<li>Residentes de zonas de alto riesgo endémico</li>\r\n</ul>\r\n<h2>Contexto epidemiológico</h2>\r\n<p>La campaña responde al incremento del 40% en casos de dengue registrado en los primeros meses de 2026, en comparación con el mismo período del año anterior. Las provincias más afectadas son Santo Domingo, Santiago, La Vega y San Cristóbal.</p>\r\n<p>El ministro de Salud hizo un llamado a la población a acudir a los centros de vacunación y a mantener las medidas de prevención como eliminar criaderos de mosquitos en los hogares.</p>', 'https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?w=1200&q=80', '', '', 1, 7, 11257, 0, 0, 'publicado', 1, 1, 0, 0, 1, '', '', '', NULL, 2, NULL, '', '', '', '2026-04-23 10:05:00', '2026-05-10 00:29:22', '2026-04-23 09:05:48', 265, 135, 0, 0, 1, NULL, NULL),
(6, 'Trump salió apresuradamente del escenario tras disparos en la Cena de Corresponsales de la Casa Blanca', 'trump-salio-apresuradamente-del-escenario-tras-disparos-en-la-cena-de-corresponsales-de-la-casa-blanca', 'El presidente de Estados Unidos, Donald Trump, fue escoltado rápidamente fuera del escenario por el Servicio Secreto tras reportes de posibles disparos durante la Cena de Corresponsales de la Casa Blanca en Washington este sábado.', 'Trump salió apresuradamente del escenario tras disparos en la Cena de Corresponsales de la Casa Blanca\r\n\r\nEl presidente de Estados Unidos, Donald Trump, fue escoltado rápidamente fuera del escenario por el Servicio Secreto tras reportes de posibles disparos durante la Cena de Corresponsales de la Casa Blanca en Washington este sábado.\r\n\r\nEl vicepresidente J. D. Vance y miembros del gabinete de Trump que también estaban presentes fueron evacuados.\r\n\r\nUna fuente dijo a CNN que Trump está a salvo, mientras que dos fuentes aseguraron que Vance salió de la cena de manera segura. De acuerdo con un funcionario de la Casa Blanca, los miembros del gabinete también están bien.\r\n\r\nVarios agentes del Servicio Secreto de Estados Unidos gritaron “¡Disparos!” durante el evento, que se realiza en el Washington Hilton, según reportes de la prensa.\r\n\r\nMás tarde, el Servicio Secreto dijo en una publicación en X que una persona está bajo custodia.\r\n\r\nTrump está en un lugar seguro y dijo a funcionarios que tiene la intención de regresar a la cena, de acuerdo con un alto funcionario del Gobierno.\r\n\r\nTrump publicó en Truth Social que “un atacante ha sido detenido” y elogió al Servicio Secreto y a las fuerzas del orden por actuar “rápida y valientemente”.\r\n\r\n“De repente, un tipo con un arma, un arma muy, muy peligrosa, empezó a disparar, y yo estaba a pocos metros de él justo cuando disparaba”, dijo Blitzer.\r\n\r\nEn una publicación posterior, el presidente dijo que regresaba a la Casa Blanca después de que las autoridades le pidieran que abandonara el lugar. Trump añadió que dará una conferencia de prensa en breve.\r\n\r\nWolf Blitzer, de CNN, dijo en vivo que estaba “a unos pocos metros de (un hombre armado) mientras disparaba”.\r\n\r\nNoticia en desarrollo…', 'assets/images/noticias/img_1777173843_ebf1ccf1.jpg', '', '', 1, 6, 4, 0, 0, 'publicado', 1, 1, 0, 0, 1, 'CNN', 'https://cnnespanol.cnn.com/2026/04/25/eeuu/trump-retirado-cena-corresponsales-casa-blanca-trax', 'https://www.youtube.com/watch?v=BncaMpDr_rA', NULL, 2, NULL, '', '', '', '2026-04-25 23:18:00', '2026-05-09 04:57:14', '2026-04-26 03:20:34', 0, 0, 0, 0, 1, NULL, NULL),
(7, 'Cumbre de Líderes de América Latina busca moneda común para 2030', 'cumbre-lideres-latinoamerica-moneda-comun-2030', 'Representantes de 15 países se reúnen en Santo Domingo para discutir la integración económica regional.', '<p>La histórica cumbre celebrada en el Centro de Convenciones del Ministerio de Relaciones Exteriores...</p>', 'https://images.unsplash.com/photo-1526948128573-703ee1aeb6fa?w=1200', 'Banderas latinoamericanas', 'Cumbre Santo Domingo 2026', 1, 1, 3203, 45, 30, 'publicado', 0, 0, 0, 0, 1, 'Cancillería RD', 'https://mirex.gob.do', NULL, NULL, 6, NULL, NULL, NULL, NULL, '2026-04-26 14:00:00', '2026-05-11 10:19:52', '2026-04-26 14:00:00', 45, 30, 0, 0, 1, NULL, NULL),
(8, 'Precios del oro alcanzan máximo histórico en mercados internacionales', 'precios-oro-maximo-historico-2026', 'La onza de oro supera los $3,000 dólares por primera vez debido a la volatilidad en las divisas tradicionales.', '<p>El mercado de metales preciosos ha reaccionado con fuerza ante los cambios en la política monetaria de la FED...</p>', 'https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?w=1200', 'Lingotes de oro', 'Gráfico de precios del oro', 1, 2, 5607, 210, 150, 'publicado', 1, 0, 0, 0, 1, 'Bloomberg News', 'https://bloomberg.com', NULL, NULL, 4, NULL, NULL, NULL, NULL, '2026-04-27 08:30:00', '2026-05-11 22:40:56', '2026-04-27 08:30:00', 210, 150, 0, 0, 1, NULL, NULL),
(9, 'Exportaciones de Zonas Francas crecen 15% en el primer cuatrimestre', 'exportaciones-zonas-francas-crecen-2026', 'El sector dispositivos médicos lidera el crecimiento de las exportaciones hacia Estados Unidos y Europa.', '<p>El Consejo Nacional de Zonas Francas de Exportación (CNZFE) reportó cifras récord durante este periodo...</p>', 'https://images.unsplash.com/photo-1566576721346-d4a3b4eaeb55?w=1200', 'Fábrica moderna', 'Planta de ensamblaje médico', 1, 2, 2105, 56, 40, 'publicado', 0, 0, 0, 0, 1, 'CNZFE', 'https://cnzfe.gob.do', NULL, NULL, 3, NULL, NULL, NULL, NULL, '2026-04-25 10:00:00', '2026-05-11 01:15:03', '2026-04-25 10:00:00', 56, 40, 0, 0, 1, NULL, NULL),
(10, 'Apple presenta las nuevas Vision Pro 2 con integración neuronal', 'apple-presenta-vision-pro-2-integracion-neuronal', 'La compañía de Cupertino revoluciona el mercado con gafas inteligentes controladas mediante señales cerebrales básicas.', '<p>En un evento sorpresa desde el Apple Park, Tim Cook mostró los avances en computación espacial...</p>', 'https://images.unsplash.com/photo-1622979135225-d2ba269cf1ac?w=1200', 'Realidad Aumentada', 'Gafas de nueva generación', 1, 3, 12402, 890, 670, 'publicado', 1, 1, 0, 0, 1, 'TechCrunch', 'https://techcrunch.com', NULL, NULL, 7, NULL, NULL, NULL, NULL, '2026-04-27 12:00:00', '2026-05-09 04:41:50', '2026-04-27 12:00:00', 890, 670, 0, 0, 1, NULL, NULL),
(11, 'Starlink alcanza cobertura del 100% en zonas rurales de República Dominicana', 'starlink-cobertura-total-zonas-rurales-rd', 'El servicio de internet satelital de Elon Musk llega a los rincones más remotos del país gracias a nuevos satélites.', '<p>Las comunidades rurales de la Cordillera Central ahora cuentan con conexión de alta velocidad...</p>', 'https://images.unsplash.com/photo-1517976487492-5750f3195933?w=1200', 'Satélites en órbita', 'Internet satelital RD', 1, 3, 8902, 340, 290, 'publicado', 0, 0, 0, 0, 1, 'SpaceX News', 'https://starlink.com', NULL, NULL, 4, NULL, NULL, NULL, NULL, '2026-04-26 09:15:00', '2026-05-11 23:00:57', '2026-04-26 09:15:00', 340, 290, 0, 0, 1, NULL, NULL),
(12, 'LIDOM anuncia expansión: Nuevas franquicias en Puerto Plata y Punta Cana', 'lidom-anuncia-expansion-nuevas-franquicias-en-puerto-plata-y-punta-cana', 'La Liga de Béisbol Profesional de la República Dominicana contará con 8 equipos para la temporada 2026-2027.', '<p>El presidente de la LIDOM confirmó que la expansión es un hecho tras el éxito financiero de los últimos años...</p>', 'assets/images/noticias/img_1777291254_fe1e425b.jpeg', 'Béisbol invernal', 'Estadio de béisbol', 1, 4, 15612, 420, 980, 'publicado', 1, 1, 0, 0, 1, 'LIDOM', 'https://lidom.com', '', NULL, 1, NULL, '', '', '', '2026-04-27 15:00:00', '2026-05-12 03:51:05', '2026-04-27 15:00:00', 420, 980, 0, 0, 1, NULL, NULL),
(13, 'Marileidy Paulino rompe récord mundial en los 400 metros planos', 'marileidy-paulino-rompe-record-mundial-en-los-400-metros-planos', 'La velocista dominicana detiene el cronómetro en 47.55 segundos durante la Liga de Diamante 2026.', '<p>En una carrera épica en Zúrich, Marileidy Paulino se consagra como la corredora más rápida de la historia...</p>', 'assets/images/noticias/img_1777296352_e632eb22.jpg', 'Atleta corriendo', 'Victoria de Marileidy Paulino', 1, 4, 35009, 2300, 4500, 'publicado', 1, 1, 0, 0, 1, 'World Athletics', 'https://worldathletics.org', '', NULL, 1, NULL, '', '', '', '2026-04-25 18:30:00', '2026-05-11 00:47:46', '2026-04-25 18:30:00', 2300, 4500, 0, 0, 1, NULL, NULL),
(14, 'Museo del Prado abre exposición inmersiva de artistas dominicanos en Madrid', 'museo-del-prado-exposicion-artistas-dominicanos', 'Obras de Guillo Pérez y Elsa Núñez se presentan por primera vez en formato digital e interactivo.', '<p>El arte dominicano cruza fronteras con una exhibición que mezcla el óleo tradicional con realidad virtual...</p>', 'https://images.unsplash.com/photo-1544531585-9847b68c8c86?w=1200', 'Museo de arte', 'Gente viendo cuadros', 1, 5, 2302, 89, 120, 'publicado', 0, 0, 0, 0, 1, 'Cultura RD', 'https://cultura.gob.do', NULL, NULL, 4, NULL, NULL, NULL, NULL, '2026-04-26 11:00:00', '2026-05-09 04:52:31', '2026-04-26 11:00:00', 89, 120, 0, 0, 1, NULL, NULL),
(15, 'Carnaval de la Vega 2026 es declarado Patrimonio Cultural Inmaterial de la Humanidad', 'carnaval-de-la-vega-patrimonio-humanidad-unesco', 'La UNESCO reconoce la riqueza cultural y la tradición de los diablos cojuelos dominicanos.', '<p>La noticia fue recibida con júbilo por los grupos carnavalescos de la provincia de La Vega...</p>', 'https://images.unsplash.com/photo-1533174072545-7a4b6ad7a6c3?w=1200', 'Carnaval dominicano', 'Máscaras de carnaval', 1, 5, 12810, 670, 890, 'publicado', 1, 0, 0, 0, 1, 'UNESCO', 'https://unesco.org', NULL, NULL, 6, NULL, NULL, NULL, NULL, '2026-04-24 16:00:00', '2026-05-11 07:15:17', '2026-04-24 16:00:00', 670, 890, 0, 0, 1, NULL, NULL),
(16, 'Misión tripulada a Marte de SpaceX aterriza con éxito en el Cráter Jezero', 'mision-tripulada-marte-spacex-exito-2026', 'Los primeros humanos en pisar suelo marciano han establecido su base temporal para una estancia de 30 días.', '<p>Histórico. Elon Musk confirma que los 4 astronautas se encuentran en perfecto estado de salud...</p>', 'https://images.unsplash.com/photo-1614728894747-a83421e2b9c9?w=1200', 'Marte', 'Paisaje marciano con base', 1, 6, 85007, 12500, 9800, 'publicado', 1, 1, 0, 0, 1, 'NASA', 'https://nasa.gov', NULL, NULL, 8, NULL, NULL, NULL, NULL, '2026-04-27 06:00:00', '2026-05-10 18:01:34', '2026-04-27 06:00:00', 12500, 9800, 0, 0, 1, NULL, NULL),
(17, 'Acuerdo de paz definitivo pone fin a las tensiones en el este de Europa', 'acuerdo-paz-definitivo-europa-este-2026', 'La firma del Tratado de Varsovia establece nuevas garantías de seguridad y fronteras desmilitarizadas.', '<p>Tras años de conflicto, las potencias mundiales han llegado a un consenso que garantiza la estabilidad regional...</p>', 'https://images.unsplash.com/photo-1541872703-74c5e443d1fe?w=1200', 'Palacio de paz', 'Firma de tratado', 1, 6, 42003, 5600, 3200, 'publicado', 0, 1, 0, 0, 1, 'Reuters', 'https://reuters.com', NULL, NULL, 10, NULL, NULL, NULL, NULL, '2026-04-25 09:00:00', '2026-05-09 04:41:16', '2026-04-25 09:00:00', 5600, 3200, 0, 0, 1, NULL, NULL),
