(2, 'El Click RD — 2026-05-06 13:02:37 — 1 registros', 1, 'INSERT INTO `noticias`\n(`titulo`,`slug`,`resumen`,`contenido`,`imagen`,`imagen_alt`,\n `imagen_caption`,`autor_id`,`categoria_id`,`estado`,`destacado`,\n `breaking`,`es_premium`,`es_opinion`,`allow_comments`,\n `fuente`,`fuente_url`,`tiempo_lectura`,\n `meta_title`,`meta_description`,`keywords`,\n `fecha_publicacion`,`fecha_creacion`)\nVALUES\n(\'Venezuela afirma ante CIJ su derecho \\\"irrenunciable\\\" sobre el Esequibo\',\'venezuela-afirma-ante-cij-su-derecho-irrenunciable-sobre-el-esequibo\',\'Venezuela tiene derecho \\\"irrenunciable\\\" a la región del Esequibo, rica en petróleo, declaró el miércoles un representante del país ante la Corte Internacional de Justicia (CIJ), durante una audiencia para resolver una antigua disputa con Guyana sobre ese territorio.La CIJ celebra en La Haya una semana de audiencias entre los dos países por el diferendo, que ha amenazado con desatar choques militares.\\\"Los derechos históricos de Venezuela son irrenunciables y Venezuela está decidida a defenderlos\',\'<p>Venezuela tiene derecho \\\"irrenunciable\\\" a la región del Esequibo, rica en petróleo, declaró el miércoles un representante del país ante la Corte Internacional de Justicia (CIJ), durante una audiencia para resolver una antigua disputa con Guyana sobre ese territorio.La CIJ celebra en La Haya una semana de audiencias entre los dos países por el diferendo, que ha amenazado con desatar choques militares.\\\"Los derechos históricos de Venezuela son irrenunciables y Venezuela está decidida a defenderlos </p>\',\'https://resources.diariolibre.com/images/2026/05/06/venezuela-afirma-ante-cij-su-derecho-irrenunciable-sobre-el-esequibo-6b0a1c2f-focus-0-0-400-300.jpg\',\'Venezuela afirma ante CIJ su derecho \\\"irrenunciable\\\" sobre el Esequibo\',NULL,1,6,\'publicado\',0,0,0,0,1,\'Diario Libre RSS\',\'https://www.diariolibre.com/rss/portada.xml\',1,NULL,NULL,NULL,\'2026-05-06 13:02:37\',\'2026-05-06 13:02:37\');\n\n', 'utilizado', 5, NULL, '2026-05-06 17:02:37'),
