INSERT INTO `videos` (`id`, `titulo`, `slug`, `descripcion`, `tipo`, `url`, `thumbnail`, `duracion`, `categoria_id`, `autor_id`, `vistas`, `destacado`, `autoplay`, `activo`, `orden`, `noticia_id`, `fecha_publicacion`, `fecha_creacion`) VALUES
(2, 'Evacúan a Donald Trump y a su esposa de reunión tras reportes de disparos en Washington', 'evacuan-a-donald-trump-y-a-su-esposa-de-reunion-tras-reportes-de-disparos-en-washington', 'Alerta en la Casa Blanca: en el interior del auditorio del hotel Hilton, en medio de una cena de corresponsales, se registraron disparos. Evacuaron a Donald Trump y a su esposa.', 'youtube', 'https://www.youtube.com/watch?v=-_VsTBSsGc8', 'https://img.youtube.com/vi/-_VsTBSsGc8/maxresdefault.jpg', 106, 6, 1, 0, 1, 0, 1, 0, NULL, '2026-04-26 04:40:00', '2026-04-26 08:40:54'),
(3, 'Trump divulga una foto del sospechoso de disparar en la cena de corresponsales', 'trump-divulga-una-foto-del-sospechoso-de-disparar-en-la-cena-de-corresponsales', 'Video oficial de Noticias Telemundo. Tras su regreso a la Casa Blanca, el mandatario divulgó en su cuenta de Truth Social una foto del presunto tirador sometido en el suelo del hotel Washington Hilton. El hombre, cuya identidad no ha sido revelada, fue hospitalizado con heridas.', 'youtube', 'https://www.youtube.com/watch?v=FX6Rte87IuY', 'https://img.youtube.com/vi/FX6Rte87IuY/maxresdefault.jpg', 85, 6, 1, 0, 1, 0, 1, 0, NULL, '2026-04-26 10:28:00', '2026-04-26 14:28:43'),
(4, 'Presidente Abinader inaugura carretera conecta a Tavera con Jarabacoa en La Vega', 'presidente-abinader-inaugura-carretera-conecta-a-tavera-con-jarabacoa-en-la-vega', 'Presidente Abinader inaugura carretera conecta a Tavera con Jarabacoa en La Vega.\n\nObra construida por EGEHID a un costo de RD$ 810.6 millones', 'youtube', 'https://www.youtube.com/watch?v=u9FqBlcP0x8', 'https://img.youtube.com/vi/u9FqBlcP0x8/maxresdefault.jpg', 311, 1, 1, 0, 1, 0, 1, 0, NULL, '2026-04-26 10:33:00', '2026-04-26 14:34:14'),
(5, 'Robot chino supera el récord mundial de media maratón en 50 minutos', 'robot-chino-supera-el-record-mundial-de-media-maraton-en-50-minutos', 'El robot humanoide Lighting completó los 21 km en solo 50 minutos, superando el récord mundial masculino. En un circuito compartido con 12 mil humanos, esta competencia demostró que la robótica ha pasado de la ficción al rendimiento real gracias a avances en IA y sistemas de energía.\n\nEste maratón funciona como un laboratorio para aplicar estas tecnologías en la industria, el rescate y la asistencia.', 'youtube', 'https://www.youtube.com/watch?v=nCyVhG01_vs', 'https://img.youtube.com/vi/nCyVhG01_vs/maxresdefault.jpg', 120, 3, 1, 0, 1, 0, 1, 0, NULL, '2026-04-26 10:37:00', '2026-04-26 14:37:59'),
(6, 'Fallido atentado contra Trump: Revelan nuevo impactante video del momento', 'fallido-atentado-contra-trump-revelan-nuevo-impactante-video-del-momento', 'En el video se aprecia cómo el atacante intenta sobrepasar los filtros de seguridad y recibe la respuesta de los elementos de seguridad.', 'youtube', 'https://youtu.be/KKBkwZmad4k?si=bbbe1xVUuKvtMNvO', 'https://img.youtube.com/vi/KKBkwZmad4k/maxresdefault.jpg', 596, 6, 5, 0, 1, 0, 1, 0, NULL, '2026-05-04 16:43:00', '2026-05-04 20:44:42'),
(7, 'Discurso proyecto minero Romero, en la provincia de San Juan', 'discurso-proyecto-minero-romero-en-la-provincia-de-san-juan', 'El presidente Luis Abinader dispone la detención inmediata de cualquier actividad relacionada con el proyecto minero Romero en la provincia de San Juan, en cumplimiento de la Ley 64-00 y en respeto a la voluntad de la ciudadanía.', 'youtube', 'https://www.youtube.com/watch?v=WQo7kQZokx8', 'https://img.youtube.com/vi/WQo7kQZokx8/maxresdefault.jpg', 78, 1, 1, 0, 1, 0, 1, 0, NULL, '2026-05-04 22:00:00', '2026-05-05 05:07:22');
